class Solution:
    def inorderTraversal(self, root: Optional[TreeNode]) -> List[int]:
        output = []

        def dfs(node):
            if not node:
                return
            if node.left:
                dfs(node.left)
            if node:
                output.append(node.val)
            if node.right:
                dfs(node.right)
        dfs(root)
        return output

class Solution:
    def climbStairs(self, n: int) -> int:
        cache = [-1] * (n+1)

        def dfs(i):
            if i == n:
                return 1
            if i > n:
                return 0
            if cache[i] != -1:
                return cache[i]
            cache[i] = dfs(i + 1) + dfs(i + 2)
            return cache[i]

        return dfs(0)

