class Solution:
    def maxDepth(self, root: Optional[TreeNode]) -> int:
        if not root:
            return 0
        else:
            return self.dfs(root, 1)

    def dfs(self, node, maxDepth):
        if node == None:
            return maxDepth

        left_depth, right_depth = maxDepth, maxDepth
        if node.left:
            left_depth = self.dfs(node.left, left_depth + 1)
        if node.right:
            right_depth = self.dfs(node.right, right_depth + 1)
        return max(left_depth, right_depth)

# Think of . as a match case when constructing the hashmap
class TrieNode:
    def __init__(self):
        self.children = {}
        self.word = False

class WordDictionary:

    def __init__(self):
        self.root = TrieNode()

    def addWord(self, word: str) -> None:
        curr = self.root
        for c in word:
            if c not in curr.children:
                curr.children[c] = TrieNode()
            curr = curr.children[c]
        curr.word = True

    def search(self, word: str) -> bool:

        def dfs(index, root: TrieNode):
            curr = root
            for i in range(index, len(word)):
                if word[i] == ".":
                    for child in curr.children.values():
                        if dfs(i+1, child):
                            return True
                    return False
                elif word[i] not in curr.children:
                    return False
                curr = curr.children[word[i]]
            return curr.word
        return dfs(0, self.root)

