# Need a "estimateConsumption" for getting output of h
# If h is too low, see if we can find a good higher middle ground
# if h is too high, vice versa
class Solution:
    def minEatingSpeed(self, piles: List[int], h: int) -> int:
        l = 1
        r = max(piles)
        output = r

        while l <= r:
            k = (l + r) // 2

            timeRequired = self.estimateConsumption(piles, k)

            if timeRequired <= h:
                output = k
                r = k - 1
            else:
                l = k + 1
        return output



    def estimateConsumption(self, piles, k) -> int:
        estimate = 0
        for p in piles:
            estimate += math.ceil(float(p / k))
        return estimate

# use prefix to solve and use the index as the liminer to go through the list via a for loop
class Solution:
    def pivotIndex(self, nums: List[int]) -> int:
        self.prefixSums = []
        prefix = 0
        for num in nums:
            prefix += num
            self.prefixSums.append(prefix)
        leftSum = 0
        rightSum = 0
        for i, _ in enumerate(nums):
            leftSum = 0 if i == 0 else self.prefixSums[i - 1]
            rightSum = 0 if i == len(nums) - 1 else self.prefixSums[-1] - self.prefixSums[i]
            if leftSum == rightSum:
                return i
        return -1

class TreeNode:
    def __init__(self):
        self.children = {}
        self.word = False


class PrefixTree:

    def __init__(self):
        self.root = TreeNode()

    def insert(self, word: str) -> None:
        curr = self.root
        for char in word:
            if char not in curr.children:
                curr.children[char] = TreeNode()
            curr = curr.children[char]
        curr.word = True


    def search(self, word: str) -> bool:
        curr = self.root
        for c in word:
            if c not in curr.children:
                return False
            curr = curr.children[c]
        return curr.word


    def startsWith(self, prefix: str) -> bool:
        curr = self.root
        for c in prefix:
            if c not in curr.children:
                return False
            curr = curr.children[c]
        return True

