class Solution:
    def isPalindrome(self, s: str) -> bool:
        left = 0
        right = len(s) - 1

        while left < right:
            while left < right and not s[left].isalnum():
                left += 1
            while left < right and not s[right].isalnum():
                right -= 1
            if s[left].lower() != s[right].lower():
                return False
            left += 1
            right -= 1
        return True

# sort of a history of min at the time
class MinStack:

    def __init__(self):
        self.stack = []
        self.minStack = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        minAtPush = min(val, self.minStack[-1] if self.minStack else val)
        self.minStack.append(minAtPush)

    def pop(self) -> None:
        self.stack.pop()
        self.minStack.pop()

    def top(self) -> int:
        return self.stack[-1]

    def getMin(self) -> int:
        return self.minStack[-1]

class Solution:

    def canPartition(self, nums: List[int]) -> bool:
        # calculate target and send it down dfs
        target = sum(nums)
        if target % 2 != 0:
            return False
        target //= 2
        matrix = [[-1] * (target + 1) for _ in range(len(nums) + 1)]

        def dfs(index, target):
            if index >= len(nums):
                return False
            if target < 0:
                return False
            if target == 0:
                return True
            curr = nums[index]
            if matrix[index][target] != -1:
                return matrix[index][target]
            matrix[index][target] = dfs(index + 1, target) or dfs(index + 1, target - curr)
            return matrix[index][target]
        return dfs(0, target)

