from collections import deque
class Solution:
    def hasPathSum(self, root: Optional[TreeNode], targetSum: int) -> bool:
        if not root:
            return False

        queue = deque([(root, targetSum - root.val)])

        while queue:
            node, curr_target = queue.popleft()
            if not node.left and not node.right and curr_target == 0:
                return True
            if node.left:
                queue.append((node.left, curr_target - node.left.val))
            if node.right:
                queue.append((node.right, curr_target - node.right.val))
        return False

# vertical first, then horizontal
class Solution:
    def searchMatrix(self, matrix: List[List[int]], target: int) -> bool:
        HEIGHT = len(matrix) - 1
        LENGTH = len(matrix[0]) - 1
        row = self.verticalBinarySearch(matrix, target, 0, HEIGHT)
        if row:
            return self.horizontalBinarySearch(row, target, 0, LENGTH)
        else:
            return False

    def verticalBinarySearch(self, matrix, target, top, bottom):
        if top > bottom:
            return None
        middleRow= (top + bottom) // 2
        left = matrix[middleRow][0]
        right = matrix[middleRow][-1]
        if target >= left and target <= right:
            return matrix[middleRow]
        elif target < left:
            return self.verticalBinarySearch(matrix, target, top, middleRow - 1)
        else:
            return self.verticalBinarySearch(matrix, target, middleRow + 1, bottom)


    def horizontalBinarySearch(self, row, target, left, right):
        if left > right:
            return False
        middle = (left + right) // 2
        if row[middle] == target:
            return True
        elif row[middle] < target:
            return self.horizontalBinarySearch(row, target, middle + 1, right)
        else:
            return self.horizontalBinarySearch(row, target, left, middle - 1)

class Solution:
    def encode(self, strs: List[str]) -> str:
        output = []
        for s in strs:
            output.append(str(len(s)))
            output.append("#")
            output.append(s)
        return "".join(output)

    def decode(self, s: str) -> List[str]:
        output = []
        i = 0
        while i < len(s):
            j = i
            while s[j] != "#":
                j += 1
            length = int(s[i:j])
            i = j + 1
            j = j + 1 + length
            word = s[i:j]
            output.append(word)
            i = j
        return output

class Solution:
    def subarraySum(self, nums: List[int], k: int) -> int:
        res, curSum = 0, 0
        prefixSums = { 0 : 1}
        for num in nums:
            curSum += num
            diff = curSum - k
            res += prefixSums.get(diff, 0)
            prefixSums[curSum] = 1 + prefixSums.get(curSum, 0)
        return res

class Solution:
    def threeSum(self, nums: List[int]) -> List[List[int]]:
        output = set()
        nums.sort()
        for i, a in enumerate(nums):
            if a > 0:
                break
            if i > 0 and nums[i] == nums[i-1]:
                continue
            l, r = i + 1, len(nums) - 1
            while l < r:
                threeSum = nums[i] + nums[l] + nums[r]
                if threeSum > 0:
                    r -= 1
                elif threeSum < 0:
                    l += 1
                else:
                    output.add((a, nums[l], nums[r]))
                    l += 1
                    r -= 1
        return [list(x) for x in output]

from collections import Counter
class Solution:
    def topKFrequent(self, nums: List[int], k: int) -> List[int]:
        counter = Counter(nums)
        counter = sorted(counter, key=counter.get, reverse=True)
        return counter[:k]

class Solution:
    def twoSum(self, nums: List[int], target: int) -> List[int]:
        hash_map = {}
        output_list = []
        for index, num in enumerate(nums):
            difference_to_target = target - num
            if difference_to_target in hash_map:
                return [hash_map[difference_to_target], index]
            hash_map[num] = index
        return output_list

